async function transform(input, context) {
  const loopResults = context.steps['foreach-item']?.results || [];

  return {
    totalProcessed: loopResults.length,
    completedAt: new Date().toISOString(),
    duration: Date.now() - new Date(context.steps.init?.produces?.startedAt || Date.now()).getTime(),
    results: loopResults.map((r, i) => ({
      index: i,
      output: r.produces?.result
    }))
  };
}
